INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'sleep_disorder_reset' LIMIT 1),
  'sleep_disorder_reset',
  1,
  'Reset the Body Clock',
  'Day 1 - Reset the Body Clock',
  13,
  '[{"type":"intro","dayNumber":1,"dayTitle":"Reset the Body Clock","goal":"Start resetting the body clock and nervous system so the brain begins recognizing the signals for sleep. Tonight’s sleep may not be perfect yet, but the body has already begun the reset process.","estimatedMinutes":13},{"type":"lesson","title":"Today''s Focus","paragraphs":["Start resetting the body clock and nervous system so the brain begins recognizing the signals for sleep. Tonight’s sleep may not be perfect yet, but the body has already begun the reset process."],"highlight":"Stay consistent and let the routine do the work."},{"type":"action_step","stepNumber":1,"title":"Morning Sunlight Exposure (10–20 Minutes)","instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","If sunlight is weak, increase exposure to 20–30 minutes."],"whyThisWorks":"Morning sunlight resets the brain’s circadian clock, which tells your body when to release melatonin at night. Without this signal, the brain stays confused about when to sleep."},{"type":"breathing_exercise","title":"Hydration + Nervous System Activation","instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This reduces stress hormones, which are one of the biggest causes of insomnia.","pattern":{"inhaleSeconds":4,"exhaleSeconds":6},"cycles":10},{"type":"exercise_routine","title":"Morning Movement (sleep Pressure Builder)","exercises":[{"name":"Perform 10 Minutes Of Light Physical Movement.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Mobility Stretches","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats (15 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups (10 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"action_step","stepNumber":2,"title":"Caffeine Control Rule","instructions":["Today follow this rule strictly:","No caffeine after 2 PM","coffee","tea","energy drinks","pre-workout drinks","Caffeine stays in the body 6–8 hours, often silently disturbing sleep."],"whyThisWorks":"Small consistent actions reinforce stability and support restful sleep."},{"type":"mindfulness_exercise","title":"Evening Nervous System Downshift","steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Let the body relax naturally.","Recommended length: 10–20 minutes."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"audio","title":"Tonight''s Guided Sleep Audio","description":"Press play during your evening wind-down or once you are in bed.","audioStoragePath":"sleep_disorder_reset/day-01.mp3","durationSeconds":610},{"type":"mindfulness_exercise","title":"Body Temperature Sleep Trick","steps":["Take a warm shower 60–90 minutes before sleep.","After the shower, your body temperature drops, which triggers natural sleepiness.","This trick is commonly used in sleep clinics."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"The Military Sleep Method (fast Sleep Technique)","steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying in a canoe on a calm lake.","The sky above you is clear and peaceful.","The water is still and quiet.","Focus on the scene while breathing slowly.","If thoughts appear, gently return to the calm image."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"The “Heavy Eyes” Method","steps":["When your eyes are closed in bed:","Keep your eyes closed.","Look slightly upward behind your eyelids.","Let your eyes become heavy.","This mimics the natural eye position that occurs right before sleep, helping the brain enter sleep","mode faster."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"journal","prompt":"What helped you most on Day 1?","helperText":"Write one or two practical observations.","followUpPrompt":"What will you repeat tomorrow?"},{"type":"close","message":"Day 1 is complete.","secondaryMessage":"You reinforced reset the body clock today."}]'::jsonb
)
ON CONFLICT (program_slug, day_number) DO UPDATE SET
  cards = EXCLUDED.cards,
  day_title = EXCLUDED.day_title,
  estimated_minutes = EXCLUDED.estimated_minutes,
  updated_at = NOW();

INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'sleep_disorder_reset' LIMIT 1),
  'sleep_disorder_reset',
  2,
  'Reducing Mental Stimulation',
  'Day 2 - Reducing Mental Stimulation',
  13,
  '[{"type":"intro","dayNumber":2,"dayTitle":"Reducing Mental Stimulation","goal":"Reduce mental stimulation and racing thoughts at night while strengthening the sleep routine. By repeating the same steps from Day 1 and adding this new technique, the brain slowly begins to associate the routine with sleep.","estimatedMinutes":13},{"type":"lesson","title":"Today''s Focus","paragraphs":["Reduce mental stimulation and racing thoughts at night while strengthening the sleep routine. By repeating the same steps from Day 1 and adding this new technique, the brain slowly begins to associate the routine with sleep."],"highlight":"Stay consistent and let the routine do the work."},{"type":"action_step","stepNumber":1,"title":"Morning Sunlight Exposure (10–20 Minutes)","instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","If sunlight is weak, increase exposure to 20–30 minutes."],"whyThisWorks":"Morning sunlight resets the brain’s circadian clock, helping the body release melatonin naturally at night. Without this signal, the brain stays confused about when to sleep."},{"type":"breathing_exercise","title":"Hydration + Nervous System Activation","instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This reduces stress hormones and relaxes the nervous system.","pattern":{"inhaleSeconds":4,"exhaleSeconds":6},"cycles":10},{"type":"exercise_routine","title":"Morning Movement (sleep Pressure Builder)","exercises":[{"name":"Perform 10 Minutes Of Light Physical Movement.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Mobility Stretches","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats (15 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups (10 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"action_step","stepNumber":2,"title":"Caffeine Control Rule","instructions":["Today follow this rule strictly:","No caffeine after 2 PM","coffee","tea","energy drinks","pre-workout drinks","Caffeine can remain in the body 6–8 hours, which can silently disturb sleep."],"whyThisWorks":"Small consistent actions reinforce stability and support restful sleep."},{"type":"mindfulness_exercise","title":"Evening Nervous System Downshift","steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the voice instructions.","Let your body relax naturally.","Recommended audio length: 10–20 minutes."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"audio","title":"Tonight''s Guided Sleep Audio","description":"Press play during your evening wind-down or once you are in bed.","audioStoragePath":"sleep_disorder_reset/day-02.mp3","durationSeconds":624},{"type":"mindfulness_exercise","title":"Body Temperature Sleep Trick","steps":["Take a warm shower 60–90 minutes before sleep.","After the shower, your body temperature drops, which naturally triggers sleepiness.","This change signals the brain that nighttime has arrived."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"The Military Sleep Method (fast Sleep Technique)","steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying on a quiet beach at sunset.","You can hear gentle waves and feel a cool breeze.","Keep breathing slowly while focusing on the scene."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"The Cognitive Shuffle","steps":["If your mind keeps thinking when trying to sleep, use this technique.","In your mind, start naming random neutral objects.","This technique distracts the brain from problem-solving mode, which keeps people awake.","The mind becomes bored and begins transitioning into sleep mode."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"journal","prompt":"What helped you most on Day 2?","helperText":"Write one or two practical observations.","followUpPrompt":"What will you repeat tomorrow?"},{"type":"close","message":"Day 2 is complete.","secondaryMessage":"You reinforced reducing mental stimulation today."}]'::jsonb
)
ON CONFLICT (program_slug, day_number) DO UPDATE SET
  cards = EXCLUDED.cards,
