INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'sleep_disorder_reset' LIMIT 1),
  'sleep_disorder_reset',
  4,
  'Reducing Night Awakenings',
  'Day 4 - Reducing Night Awakenings',
  14,
  '[{"type":"intro","dayNumber":4,"dayTitle":"Reducing Night Awakenings","goal":"Improve sleep continuity and reduce middle-of-the-night awakenings.","estimatedMinutes":14},{"type":"lesson","title":"Today''s Focus","paragraphs":["Improve sleep continuity and reduce middle-of-the-night awakenings."],"highlight":"fewer night wake-ups"},{"type":"action_step","stepNumber":1,"title":"Morning Sunlight Exposure (10–20 Minutes)","instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","Try to expose your eyes to full outdoor daylight, not through a window, because glass blocks part of","the light signal that helps regulate your body clock."],"whyThisWorks":"Morning sunlight resets the brain’s circadian rhythm, helping your body release melatonin at night and improve sleep timing."},{"type":"breathing_exercise","title":"Hydration + Nervous System Activation","instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This lowers stress hormones and calms the nervous system.","pattern":{"inhaleSeconds":4,"exhaleSeconds":6},"cycles":10},{"type":"exercise_routine","title":"Morning Movement (sleep Pressure Builder)","exercises":[{"name":"Perform 10 Minutes Of Light Physical Movement.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Mobility Stretches","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats (15 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups (10 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"action_step","stepNumber":2,"title":"Caffeine Control Rule","instructions":["Follow this rule strictly:","No caffeine after 2 PM","coffee","tea","energy drinks","pre-workout drinks","Caffeine can remain active in the body 6–8 hours, disturbing sleep cycles."],"whyThisWorks":"Small consistent actions reinforce stability and support restful sleep."},{"type":"mindfulness_exercise","title":"Evening Nervous System Downshift","steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Allow your body to relax naturally.","Recommended audio length: 10–20 minutes."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"audio","title":"Tonight''s Guided Sleep Audio","description":"Press play during your evening wind-down or once you are in bed.","audioStoragePath":"sleep_disorder_reset/day-04.mp3","durationSeconds":647},{"type":"mindfulness_exercise","title":"Body Temperature Sleep Trick","steps":["Take a warm shower 60–90 minutes before sleep.","After the shower, the body experiences a natural drop in temperature, which signals the brain that it","is time to sleep."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"The Military Sleep Method (fast Sleep Technique)","steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying in a quiet field under a clear starry sky.","The night air is calm and peaceful.","Everything around you feels safe and quiet.","Focus on the scene while breathing slowly."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"The “15-Minute Reset Rule”","steps":["If you wake up during the night and cannot fall asleep within about 15 minutes, do this:","Get out of bed quietly.","Go to a dimly lit room.","Sit or read something calm (no phone or bright screens).","Stay there for 5–10 minutes.","Return to bed when you feel sleepy."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"journal","prompt":"What helped you most on Day 4?","helperText":"Write one or two practical observations.","followUpPrompt":"What will you repeat tomorrow?"},{"type":"close","message":"Day 4 is complete.","secondaryMessage":"fewer night wake-ups"}]'::jsonb
)
