INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'sleep_disorder_reset' LIMIT 1),
  'sleep_disorder_reset',
  5,
  'Improving Deep Sleep Quality',
  'Day 5 - Improving Deep Sleep Quality',
  15,
  '[{"type":"intro","dayNumber":5,"dayTitle":"Improving Deep Sleep Quality","goal":"Improve deep sleep quality and physical relaxation so the body can enter deeper restorative sleep cycles.","estimatedMinutes":15},{"type":"lesson","title":"Today''s Focus","paragraphs":["Improve deep sleep quality and physical relaxation so the body can enter deeper restorative sleep cycles."],"highlight":"falling asleep faster"},{"type":"action_step","stepNumber":1,"title":"Morning Sunlight Exposure (10–20 Minutes)","instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","Combine sunlight exposure with a short walk to strengthen the signal to your body clock."],"whyThisWorks":"Morning sunlight resets the brain’s circadian rhythm, helping the body release melatonin naturally at night."},{"type":"breathing_exercise","title":"Hydration + Nervous System Activation","instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This helps lower stress hormones and relax the nervous system.","pattern":{"inhaleSeconds":4,"exhaleSeconds":6},"cycles":10},{"type":"exercise_routine","title":"Morning Movement (sleep Pressure Builder)","exercises":[{"name":"Perform 10 Minutes Of Light Physical Movement.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Mobility Stretches","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats (15 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups (10 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"action_step","stepNumber":2,"title":"Caffeine Control Rule","instructions":["Follow this rule strictly:","No caffeine after 2 PM","coffee","tea","energy drinks","pre-workout drinks","Caffeine can remain active in the body 6–8 hours, affecting deep sleep cycles."],"whyThisWorks":"Small consistent actions reinforce stability and support restful sleep."},{"type":"mindfulness_exercise","title":"Evening Nervous System Downshift","steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Allow your body to relax naturally.","Recommended length: 10–20 minutes."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"audio","title":"Tonight''s Guided Sleep Audio","description":"Press play during your evening wind-down or once you are in bed.","audioStoragePath":"sleep_disorder_reset/day-05.mp3","durationSeconds":658},{"type":"mindfulness_exercise","title":"Body Temperature Sleep Trick","steps":["Take a warm shower 60–90 minutes before sleep.","After the shower, your body temperature drops slightly.","This temperature drop signals the brain to prepare for sleep and melatonin release."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"The Military Sleep Method (fast Sleep Technique)","steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying in a quiet cabin during gentle rain.","You can hear the soft sound of rain on the roof.","Everything around you feels calm and safe.","Focus on the sound and scene while breathing slowly."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"The “Feet Warmth Trick”","steps":["Cold feet can actually make it harder for the body to fall asleep.","Before going to bed:","wear light socks","or","place a warm blanket over your feet"],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"journal","prompt":"What helped you most on Day 5?","helperText":"Write one or two practical observations.","followUpPrompt":"What will you repeat tomorrow?"},{"type":"close","message":"Day 5 is complete.","secondaryMessage":"falling asleep faster"}]'::jsonb
)
