  21,
  '[{"type":"intro","dayNumber":21,"dayTitle":"Long-Term Sleep Stability","goal":"Lock in the sleep habits and routines developed during the past 21 days so they continue working long term.","estimatedMinutes":21},{"type":"lesson","title":"Today''s Focus","paragraphs":["Lock in the sleep habits and routines developed during the past 21 days so they continue working long term."],"highlight":"consistent sleep timing"},{"type":"action_step","stepNumber":1,"title":"Morning Sunlight Exposure (10–20 Minutes)","instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","Combine sunlight exposure with 10–15 minutes of walking."],"whyThisWorks":"Morning sunlight keeps your circadian rhythm stable, helping the body release melatonin at the correct time every night."},{"type":"breathing_exercise","title":"Hydration + Nervous System Activation","instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This lowers stress hormones and prepares the nervous system for the day.","pattern":{"inhaleSeconds":4,"exhaleSeconds":6},"cycles":10},{"type":"exercise_routine","title":"Final Movement Routine (sleep Pressure Builder)","exercises":[{"name":"Total Movement Time: 50–55 Minutes","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"30 Minutes Continuous Walking.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"35 Reps × 6 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"25 Reps × 5 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Jumping Jacks","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"65 Reps × 5 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Plank Hold","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"60 Seconds × 5 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Standing Forward Stretch","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"action_step","stepNumber":2,"title":"Caffeine Control Rule","instructions":["Continue following this rule:","No caffeine after 2 PM","coffee","tea","energy drinks","pre-workout drinks","Reducing late caffeine protects sleep quality and sleep depth."],"whyThisWorks":"Small consistent actions reinforce stability and support restful sleep."},{"type":"mindfulness_exercise","title":"Evening Nervous System Downshift","steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Allow your body to relax naturally.","Recommended length: 10–20 minutes."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"audio","title":"Tonight''s Guided Sleep Audio","description":"Press play during your evening wind-down or once you are in bed.","audioStoragePath":"sleep_disorder_reset/day-21.mp3","durationSeconds":658},{"type":"mindfulness_exercise","title":"Body Temperature Sleep Trick","steps":["Take a warm shower 60–90 minutes before sleep.","After the shower, the body temperature drops slightly, signaling the brain that it is time for sleep."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"The Military Sleep Method (fast Sleep Technique)","steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying beside a quiet lake under a clear night sky.","The water is still and the night air is peaceful.","Focus on the calm scene while breathing slowly."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"The “Sleep Anchor”","steps":["This technique helps the brain associate one consistent cue with sleep.","Choose one simple action you will repeat every night before sleep, such as:","turning on your meditation audio","dimming the lights","taking 5 slow breaths","Repeat the same action every night before sleeping."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"journal","prompt":"What helped you most on Day 21?","helperText":"Write one or two practical observations.","followUpPrompt":"What will you repeat tomorrow?"},{"type":"close","message":"Day 21 is complete.","secondaryMessage":"consistent sleep timing"}]'::jsonb
